{
  "operations": {
    "view": [
      { "impl": "index.html", "type": "web" }
    ]
  },
  "runtimeManifest": {
    "packages": {
      "${extensionPoint}": {
        "license": "Apache-2.0",
        "actions": {}
      }
    }
  },
  "_note": "Extension config for ${extensionPoint}. Reference from app.config.yaml: extensions.${extensionPoint}.$include = ext-config/${extensionPoint}.json"
}

/*
 * ${actionName} — Adobe I/O Runtime action (OpenWhisk).
 * `main` receives the merged default + invocation params; return a JSON-serializable result.
 */
const { Core } = require('@adobe/aio-sdk');

async function main(params) {
  const logger = Core.Logger('${actionName}', { level: params.LOG_LEVEL || 'info' });
  try {
    logger.info('${actionName} invoked');
    // ... your logic here ...
    return { statusCode: 200, body: { ok: true, action: '${actionName}' } };
  } catch (error) {
    logger.error(error);
    return { statusCode: 500, body: { error: 'server error' } };
  }
}

exports.main = main;

/*
 * ${actionName} — App Builder WEB action (HTTP-invokable).
 * Returns { statusCode, body }. Validate required params; keep secrets in inputs/.env.
 */
const { Core } = require('@adobe/aio-sdk');

async function main(params) {
  const logger = Core.Logger('${actionName}', { level: params.LOG_LEVEL || 'info' });
  try {
    // const required = ['param']; for (const p of required) if (!params[p]) ...
    logger.info('${actionName} (web) invoked');
    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: { ok: true, action: '${actionName}' },
    };
  } catch (error) {
    logger.error(error);
    return { statusCode: 500, body: { error: 'server error' } };
  }
}

exports.main = main;

/* ${componentName} — App Builder web UI (React Spectrum). */
import React from 'react';
import { Provider, defaultTheme, View, Heading, Content } from '@adobe/react-spectrum';

export default function ${componentName}() {
  return (
    <Provider theme={defaultTheme} colorScheme="light">
      <View padding="size-300">
        <Heading level={2}>${componentName}</Heading>
        <Content>Your App Builder UI starts here.</Content>
      </View>
    </Provider>
  );
}
